class Solution(object):
    def btreeGameWinningMove(self, root, n, x):
        def find_and_count(node, target):
            if not node:
                return None, 0
            if node.val == target:
                left_count = count_nodes(node.left)
                right_count = count_nodes(node.right)
                parent_count = n - 1 - left_count - right_count
                return (left_count, right_count, parent_count), 0
            left_result, _ = find_and_count(node.left, target)
            if left_result:
                return left_result, 0
            return find_and_count(node.right, target)
        def count_nodes(node):
            if not node:
                return 0
            return 1 + count_nodes(node.left) + count_nodes(node.right)
        counts, _ = find_and_count(root, x)
        left, right, parent = counts
        return max(left, right, parent) > n // 2
